document.addEventListener("DOMContentLoaded",()=>{const searchInput=document.getElementById("faqSearch");const clearSearchButton=document.getElementById("clearFaqSearch");const clearAllButton=document.getElementById("clearFaqFilters");const resultCount=document.getElementById("faqResultCount");const noResults=document.getElementById("faqNoResults");const filters=Array.from(document.querySelectorAll(".faq-filter"));const items=Array.from(document.querySelectorAll(".faq-item"));const categorySections=Array.from(document.querySelectorAll(".faq-category-section"));let activeCategory="all";const normalize=(value)=>value.toLowerCase().replace(/[^a-z0-9\s]/g," ").replace(/\s+/g," ").trim();const setAccordion=(item,shouldOpen)=>{const button=item.querySelector(".faq-question");const answer=item.querySelector(".faq-answer");if(!button||!answer)return;button.setAttribute("aria-expanded",String(shouldOpen));answer.hidden=!shouldOpen;item.classList.toggle("is-open",shouldOpen);};items.forEach((item)=>{const button=item.querySelector(".faq-question");button?.addEventListener("click",()=>{const isOpen=button.getAttribute("aria-expanded")==="true";setAccordion(item,!isOpen);});});const applyFilters=()=>{const term=normalize(searchInput?.value||"");let visible=0;items.forEach((item)=>{const categoryMatch=activeCategory==="all"||item.dataset.category===activeCategory;const textMatch=!term||normalize(item.textContent).includes(term);const shouldShow=categoryMatch&&textMatch;item.hidden=!shouldShow;item.classList.toggle("is-filtered-out",!shouldShow);if(shouldShow)visible+=1;});categorySections.forEach((section)=>{const visibleItems=section.querySelectorAll(".faq-item:not([hidden])").length;section.hidden=visibleItems===0;});if(noResults)noResults.hidden=visible!==0;if(resultCount){if(visible===42&&activeCategory==="all"&&!term){resultCount.textContent="Showing all 42 questions";}else{resultCount.textContent=`${visible} ${visible === 1 ? "question" : "questions"} found`;}}};filters.forEach((filter)=>{filter.addEventListener("click",()=>{activeCategory=filter.dataset.category||"all";filters.forEach((button)=>{const selected=button===filter;button.classList.toggle("is-active",selected);button.setAttribute("aria-pressed",String(selected));});applyFilters();document.querySelector(".faq-content-grid")?.scrollIntoView({behavior:"smooth",block:"start"});});});searchInput?.addEventListener("input",applyFilters);clearSearchButton?.addEventListener("click",()=>{searchInput.value="";applyFilters();searchInput.focus();});const resetAll=()=>{activeCategory="all";if(searchInput)searchInput.value="";filters.forEach((button)=>{const selected=button.dataset.category==="all";button.classList.toggle("is-active",selected);button.setAttribute("aria-pressed",String(selected));});applyFilters();};clearAllButton?.addEventListener("click",resetAll);document.querySelectorAll("[data-open-faq]").forEach((button)=>{button.addEventListener("click",()=>{resetAll();const target=document.getElementById(button.dataset.openFaq||"");if(!target)return;setAccordion(target,true);window.setTimeout(()=>target.scrollIntoView({behavior:"smooth",block:"center"}),80);});});const openHashQuestion=()=>{if(!window.location.hash.startsWith("#faq-"))return;const target=document.querySelector(window.location.hash);if(!target?.classList.contains("faq-item"))return;resetAll();setAccordion(target,true);window.setTimeout(()=>target.scrollIntoView({behavior:"smooth",block:"center"}),350);};window.addEventListener("hashchange",openHashQuestion);applyFilters();openHashQuestion();});